-- в”Ђв”Ђ Binti в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Binti is cloud-based case management software, a CCWIS, that helps foster care, adoption, and child welfare agencies manage intake, licensing, placements, and eligibility.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Growing venture-backed company serving 300 plus agencies; exact employee count not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Binti Review: Foster Care and Child Welfare Case Management$q$, seo_title),
  seo_meta_description = COALESCE($q$Binti is cloud case management software for child welfare agencies, covering intake, licensing, placements, and eligibility. See features, pricing, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Binti is a cloud-based, modular case management platform, known as a Comprehensive Child Welfare Information System (CCWIS), built specifically for foster care, adoption, and child welfare agencies. It was founded in 2015 by Felicia Curcuru and Gabe Kopley, with Curcuru serving as CEO, and is headquartered in San Francisco, California. Binti's mission is explicitly framed around helping every child find a safe, loving, and stable family, and the company describes itself as mission-driven technology for the child welfare sector. The product covers the end-to-end child welfare workflow through separate but connectable modules, including Intake, Community Crisis Response (Investigations), Licensing, Placements, Case Management, and Eligibility and Payments, alongside a Family First Prevention Services Module for federal compliance, a Family Finding Module to help locate relatives and kin, and dedicated portals for youth in care and CASAs (court-appointed special advocates). Agencies can purchase individual modules or bundle them together, paying through an all-inclusive annual subscription that includes unlimited users, configuration services, and a live chat help desk for both agency staff and families. Binti reports that it has scaled to serve more than 300 to 450 child welfare agencies across roughly 33 to 34 US states plus the District of Columbia, including a number of statewide implementations, with over 12,000 social workers using Binti as their primary daily workspace and the platform touching over 30 percent of children in the US child welfare system according to company figures. Reported outcomes include an average 30 percent increase in the number of quality foster families licensed in an agency's first year, using 18 percent less time, and up to a 40 percent reduction in social workers' administrative time. Binti has raised institutional venture funding, including a Series A round of 12 million dollars in 2021 and a Series B round of 16 million dollars in 2022, from investors such as Founders Fund, First Round Capital, and Kapor Capital. For public sector procurement, Binti partners with Carahsoft as its public sector distributor, making the software available to state and local agencies through contract vehicles such as NASPO ValuePoint, the National Cooperative Purchasing Alliance, E and I Cooperative Services, and OMNIA Partners. Binti does not publish public list pricing; prospective agencies must contact Binti or Carahsoft directly for a custom quote based on which modules and how many users are needed.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8472f3a3-648f-4ce3-a589-dce2fb48bd28';

