-- в”Ђв”Ђ Bitnami в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Bitnami, owned by Broadcom via VMware, is a catalog of pre-packaged open-source application containers and Helm charts; since late 2025, most production-grade images require a paid Bitnami Secure Images subscription, with only a small free tier for latest-tag, non-production use.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Originally a small startup (Bitrock); now operated as part of Broadcom, a large multinational technology company$q$, company_size),
  headquarters = COALESCE($q$Originally Seville, Spain (as Bitrock); now operated as part of Broadcom and VMware, with Broadcom headquartered in Palo Alto, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bitnami Review 2026: What Is Still Free After Broadcom Changes$q$, seo_title),
  seo_meta_description = COALESCE($q$Bitnami offers pre-packaged open-source app containers and Helm charts. See what changed under Broadcom, what is still free, and Secure Images pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bitnami is a catalog of pre-packaged, ready-to-run open-source application stacks, container images, and Helm charts, historically prized for making software like databases, content management systems, and developer tools instantly deployable. It traces back to 2011, sponsored by a company called Bitrock, founded in Seville, Spain by Daniel Lopez Ridruejo and Erica Brescia, and it received early Y Combinator-backed seed funding. VMware acquired Bitnami (along with related Bitrock assets such as InstallBuilder) on May 15, 2019. VMware itself was later acquired by Broadcom in November 2023, bringing Bitnami under Broadcom's ownership. For most of its history, Bitnami was known for offering hundreds of free, versioned container images and Helm charts that developers and organizations could pull and deploy without cost. That changed significantly starting in 2025: Broadcom announced that, effective around August 28, 2025 (later the full removal of the old public catalog was pushed to around September 29, 2025), it would restructure the Bitnami container catalog into three distinct repositories. The main docker.io/bitnami repository now hosts only a limited set of hardened images available exclusively with latest tags, explicitly intended for development and non-production use, reportedly around 44 images. A new docker.io/bitnamilegacy repository archives all historical image versions but receives no further security updates. A docker.io/bitnamisecure repository provides preview access tied to the paid offering. Production-grade, versioned, and hardened images now require a paid Bitnami Secure Images (also referred to as Bitnami Premium) subscription, which bundles unlimited container pulls, access to versioned and long-term-support images, continuous vulnerability scanning and patching, software bills of materials, VEX documentation, and enterprise support. Third-party reporting cites annual subscription costs in the range of roughly 50,000 to 72,000 dollars, with at least one AWS Marketplace listing around 6,000 dollars per month on a 12-month contract; Broadcom has not published a single official public price list, so these figures should be treated as third-party estimates rather than confirmed vendor pricing. Existing Bitnami Helm charts remain published as OCI artifacts at docker.io/bitnamicharts, but they no longer receive updates and may require overriding bundled image references with currently valid images to deploy successfully. In short, as of 2026 Bitnami is best described as a freemium, largely paywalled service: a genuinely useful but narrow free tier still exists for development and testing, while the broad, free, production-grade catalog that made Bitnami famous no longer exists in its historical form.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bdf4149c-1a2a-4360-bde4-d355b0d33fb6';

