INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Visual Workflow Editor$q$, $q$Configure build pipelines via a visual editor or underlying YAML configuration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Steps Marketplace$q$, $q$Hundreds of prebuilt community and official integration steps for testing, code signing, and deployment.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$macOS and Linux Build Machines$q$, $q$Access to Apple silicon and Linux virtual machines sized for different build workloads.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Build Caching$q$, $q$Speeds up repeat builds by caching dependencies and build artifacts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Release Management Add-On$q$, $q$Manages app store submissions and release rollouts from within the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Concurrent Builds and Team Roles$q$, $q$Supports multiple simultaneous builds and team member management depending on plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Enterprise and Self-Hosted Options$q$, $q$Dedicated or private cloud deployment, including self-hosting on AWS for large organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Purpose-built for mobile CI/CD rather than a general-purpose pipeline retrofitted for mobile$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Large marketplace of integration steps covering testing, code signing, and app store deployment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Offers a genuinely usable free Hobby tier for individual developers and small projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Supports both macOS and Linux build machines, including different machine sizes for performance needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Enterprise tier offers dedicated, private cloud, and self-hosted deployment options$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Backed by a large, established customer base and remote-first team with offices across three countries$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Paid plans can become expensive quickly for teams needing higher concurrency or macOS build minutes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Some valuable features, like advanced Build Cache and Release Management tiers, are separately priced add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Free Hobby tier is limited to a single private app and modest monthly credits$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Pricing structure with multiple tiers and add-ons can be complex to estimate total cost upfront$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Enterprise pricing is custom and not transparently published$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$What is Bitrise used for?$q$, $q$Bitrise is a CI/CD platform specifically designed to automate building, testing, and deploying iOS and Android mobile apps.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$When was Bitrise founded?$q$, $q$Bitrise was founded in 2014 by Barnabas Birmacher, Viktor Benei, and Daniel Balla.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Where is Bitrise headquartered?$q$, $q$Bitrise is headquartered in Budapest, Hungary, and also maintains a US office in San Francisco.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Does Bitrise have a free plan?$q$, $q$Yes, the Hobby plan is free and includes one private app, limited concurrency, and a monthly credit allotment.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$How much do Bitrise paid plans cost?$q$, $q$Paid plans start with Starter at roughly 89 to 99 dollars per month, followed by Pro at roughly 200 to 218 dollars per month, with custom Enterprise pricing above that.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Does Bitrise support both iOS and Android?$q$, $q$Yes, it provides build machines and workflow steps for both iOS (macOS machines) and Android (Linux machines) development.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Does Bitrise offer self-hosted or enterprise deployment?$q$, $q$Yes, the Enterprise tier offers dedicated and private cloud options, including a self-hosted AWS deployment capability.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Are add-ons like Build Cache and Release Management included in the base price?$q$, $q$No, advanced Build Cache and Release Management tiers are priced as separate add-ons on top of the base plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Automating Mobile App Builds$q$, $q$Mobile teams use Bitrise workflows to automatically build, test, and sign iOS and Android apps on every code push.$q$, $q$Mobile app development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Streamlining App Store Releases$q$, $q$Teams use Bitrise's Release Management add-on to manage versioning and submissions to the Apple App Store and Google Play from one pipeline.$q$, $q$Release engineers and mobile DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Scaling CI for Large Mobile Organizations$q$, $q$Enterprises with high build volume use Bitrise's Enterprise tier for dedicated or self-hosted infrastructure and higher concurrency limits.$q$, $q$Enterprise engineering organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Hobby$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 private app","Up to 5 concurrent builds","90-minute build timeout","300 credits per month","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Starter$q$, $q$89 to 99 dollars per month depending on annual or monthly billing$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 3 concurrencies","Up to 10 team members","2 private apps","210-minute build timeout","Linux Medium and Apple silicon Medium machines"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Pro$q$, $q$200 to 218 dollars per month depending on annual or monthly billing$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 10 macOS and 30 Linux concurrencies","Unlimited team members","Unlimited private apps","210-minute build timeout","Large Apple silicon and Linux machines"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$Enterprise$q$, $q$Custom; reported to start around 2000 dollars per month for high build volume$q$, $q$Annual contract$q$, NULL, $q$["Flexible concurrency","Unlimited team members","Up to 4-hour build timeout","Dedicated or private cloud options","Self-hosted AWS capability"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$overview$q$, $q$What Is Bitrise$q$, 2, ARRAY[$q$Bitrise is a mobile DevOps platform that provides continuous integration and continuous delivery specifically built around the workflows of iOS and Android app development. Rather than adapting a general-purpose CI/CD tool for mobile, it was designed from the ground up to handle mobile-specific needs like code signing, provisioning profiles, and app store submissions.$q$, $q$The company was founded in 2014 by Barnabas Birmacher, Viktor Benei, and Daniel Balla, and is headquartered in Budapest, Hungary, with additional offices in San Francisco and London as part of a remote-first organizational structure.$q$, $q$Bitrise reports serving more than 6,000 customers and over 100,000 developers, with more than 2 million builds processed on its infrastructure each month, making it one of the more established players specifically in the mobile CI/CD category.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Bitrise is a visual workflow editor, backed by an underlying YAML configuration, that teams use to assemble build, test, and deployment pipelines from a large marketplace of prebuilt integration steps covering testing frameworks, code signing, and app store deployment tasks.$q$, $q$Because mobile builds require different hardware for different platforms, Bitrise offers both macOS build machines (needed to build and sign iOS apps) and Linux build machines (for Android builds), available in multiple performance tiers depending on the plan.$q$, $q$Additional capabilities include build caching to speed up repeat builds by reusing dependencies and artifacts, a Release Management add-on to coordinate app store submissions and rollouts from within the platform, and support for running multiple builds concurrently, with concurrency limits and team member counts varying by subscription tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f1c9f3c-0bbc-4447-8e8b-6308460bfc72', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bitrise offers a free Hobby plan that includes one private app, up to five concurrent builds, a 90-minute build timeout, and 300 credits per month with community-level support, making it usable for individual developers or small side projects.$q$, $q$Paid plans start with Starter at roughly 89 to 99 dollars per month depending on monthly or annual billing, offering up to three concurrencies, up to ten team members, two private apps, and access to medium-sized Linux and Apple silicon build machines. The Pro plan, around 200 to 218 dollars per month, raises concurrency limits substantially, removes the team member and private app caps, and adds access to larger build machines.$q$, $q$Large organizations can move to a custom Enterprise plan offering flexible concurrency, unlimited team members, longer build timeouts of up to four hours, and dedicated, private cloud, or self-hosted AWS deployment options; third-party reporting suggests Enterprise pricing can start around 2,000 dollars per month for high build volumes. Some features, including advanced Build Cache tiers and Release Management beyond the basic level, are billed as separate add-ons on top of the base plan.$q$]::text[], 2);
